interface Summary {
  totalIncome: number;
  totalExpense: number;
  balance: number;
}

____ computeSummary(txs: Transaction[]): Summary {
  let totalIncome = 0;
  let totalExpense = 0;
  for (const t of txs) {
    if (t.type === 'INCOME') totalIncome += t.amount;
    else totalExpense += t.amount;
  }
  return {
    totalIncome,
    totalExpense,
    balance: totalIncome - totalExpense,
  };
}

